import React, { useCallback, useEffect, useMemo, useState } from 'react'
import { productService } from '../../services/api'
import { showToast } from '../../utils/toast'
import PondChartCard from '../../components/charts/PondChartCard'
import '../../styles/product-management.css'

const emptyCategoryForm = {
  categoryName: '',
  note: '',
}

const emptyProductForm = {
  categoryId: '',
  categoryName: '',
  productName: '',
  unit: '',
  supplier: '',
  unitPrice: '',
  note: '',
}

const emptyOverview = {
  totalCategories: 0,
  totalProducts: 0,
  totalSuppliers: 0,
  topCategory: null,
  categoryStats: [],
  supplierStats: [],
  topProducts: [],
}

const PAGE_SIZE = 8

const formatDateTime = (value) => {
  if (!value) return '-'
  const date = new Date(value)
  if (Number.isNaN(date.getTime())) return value

  return new Intl.DateTimeFormat('vi-VN', {
    day: '2-digit',
    month: '2-digit',
    year: 'numeric',
    hour: '2-digit',
    minute: '2-digit',
    timeZone: 'Asia/Ho_Chi_Minh',
  }).format(date)
}

const formatCurrency = (value) => {
  const amount = Number(value || 0)
  return `${amount.toLocaleString('vi-VN')} đ`
}

const normalizeText = (value) => String(value || '').trim().toLowerCase()

const createPalette = (baseColors) => (index) => baseColors[index % baseColors.length]

const pickCategoryColor = createPalette(['#2563eb', '#10b981', '#f59e0b', '#8b5cf6', '#06b6d4', '#ef4444'])
const pickSupplierColor = createPalette(['#0ea5e9', '#22c55e', '#f97316', '#a855f7', '#f43f5e', '#64748b'])
const pickProductColor = createPalette(['#0284c7', '#0f766e', '#f59e0b', '#7c3aed', '#16a34a', '#ef4444'])

const ProductManagementPage = ({ roleLabel = 'Owner' }) => {
  const [overview, setOverview] = useState(emptyOverview)
  const [categories, setCategories] = useState([])
  const [products, setProducts] = useState([])
  const [loading, setLoading] = useState(true)

  const [activeTab, setActiveTab] = useState('products')

  const [categorySearch, setCategorySearch] = useState('')
  const [categoryFilter, setCategoryFilter] = useState('ALL')

  const [productSearch, setProductSearch] = useState('')
  const [supplierSearch, setSupplierSearch] = useState('')
  const [productCategoryFilter, setProductCategoryFilter] = useState('ALL')

  const [categoryPage, setCategoryPage] = useState(1)
  const [productPage, setProductPage] = useState(1)

  const [showCategoryModal, setShowCategoryModal] = useState(false)
  const [showProductModal, setShowProductModal] = useState(false)

  const [categoryForm, setCategoryForm] = useState(emptyCategoryForm)
  const [productForm, setProductForm] = useState(emptyProductForm)

  const [editingCategoryId, setEditingCategoryId] = useState(null)
  const [editingProductId, setEditingProductId] = useState(null)

  const [savingCategory, setSavingCategory] = useState(false)
  const [savingProduct, setSavingProduct] = useState(false)

  const fetchData = useCallback(async () => {
    try {
      setLoading(true)

      const [overviewRes, categoriesRes, productsRes] = await Promise.all([
        productService.getProductOverview(),
        productService.getProductCategories(),
        productService.getProducts(),
      ])

      setOverview(overviewRes?.data?.data || emptyOverview)
      setCategories(categoriesRes?.data?.data || [])
      setProducts(productsRes?.data?.data || [])
    } catch (err) {
      showToast({
        title: err?.response?.data?.message || 'Không tải được dữ liệu',
        type: 'error',
      })
    } finally {
      setLoading(false)
    }
  }, [])

  useEffect(() => {
    fetchData()
  }, [fetchData])

  const totalSuppliers = useMemo(() => {
    const suppliers = new Set(
      products
        .map((item) => String(item.supplier || '').trim())
        .filter(Boolean)
    )

    return suppliers.size
  }, [products])

  const filteredCategories = useMemo(() => {
    return categories.filter((item) => {
      const matchesSearch =
        !categorySearch ||
        normalizeText(item.category_name).includes(normalizeText(categorySearch))

      const count = Number(item.product_count || 0)

      const matchesFilter =
        categoryFilter === 'ALL'
          ? true
          : categoryFilter === 'HAS_PRODUCTS'
            ? count > 0
            : count === 0

      return matchesSearch && matchesFilter
    })
  }, [categories, categorySearch, categoryFilter])

  const filteredProducts = useMemo(() => {
    return products.filter((item) => {
      const matchesProduct =
        !productSearch ||
        normalizeText(item.product_name).includes(normalizeText(productSearch))

      const matchesSupplier =
        !supplierSearch ||
        normalizeText(item.supplier).includes(normalizeText(supplierSearch))

      const matchesCategory =
        productCategoryFilter === 'ALL' ||
        String(item.category_id) === String(productCategoryFilter)

      return matchesProduct && matchesSupplier && matchesCategory
    })
  }, [products, productSearch, supplierSearch, productCategoryFilter])

  const categoryTotalPages = Math.max(1, Math.ceil(filteredCategories.length / PAGE_SIZE))
  const productTotalPages = Math.max(1, Math.ceil(filteredProducts.length / PAGE_SIZE))

  const categoryPageSafe = Math.min(categoryPage, categoryTotalPages)
  const productPageSafe = Math.min(productPage, productTotalPages)

  const paginatedCategories = filteredCategories.slice(
    (categoryPageSafe - 1) * PAGE_SIZE,
    categoryPageSafe * PAGE_SIZE
  )

  const paginatedProducts = filteredProducts.slice(
    (productPageSafe - 1) * PAGE_SIZE,
    productPageSafe * PAGE_SIZE
  )

  const categoryChartData = useMemo(() => {
    return (overview.categoryStats || []).map((item, index) => ({
      label: item.label,
      value: Number(item.value || 0),
      color: pickCategoryColor(index),
    }))
  }, [overview.categoryStats])

  const supplierChartData = useMemo(() => {
    return (overview.supplierStats || []).map((item, index) => ({
      label: item.label,
      value: Number(item.value || 0),
      color: pickSupplierColor(index),
    }))
  }, [overview.supplierStats])

  const productChartData = useMemo(() => {
    return (overview.topProducts || []).map((item, index) => ({
      label: item.label,
      value: Number(item.value || 0),
      color: pickProductColor(index),
    }))
  }, [overview.topProducts])

  if (loading) {
    return (
      <div className="dashboard product-management-page">
        <div className="flex-center" style={{ height: '100vh' }}>
          <div className="spinner"></div>
        </div>
      </div>
    )
  }

  return (
    <div className="dashboard product-management-page">

      <div className="page-header">
        <div>
          <h1>Quản lý sản phẩm</h1>
          <p>Quản lý danh mục và sản phẩm sử dụng trong hệ thống trại nuôi</p>
        </div>

        <div className="page-header-actions">
          <button className="btn btn-primary" onClick={() => setShowProductModal(true)}>
            + Thêm sản phẩm
          </button>

          <button className="btn btn-secondary" onClick={() => setShowCategoryModal(true)}>
            + Thêm danh mục
          </button>
        </div>
      </div>

      <div className="dashboard-stats-grid">

        <div className="dashboard-stat-card primary">
          <div className="dashboard-stat-icon">📂</div>

          <div>
            <span>Tổng danh mục</span>
            <strong>{overview.totalCategories}</strong>
            <small>Dữ liệu theo trại {roleLabel}</small>
          </div>
        </div>

        <div className="dashboard-stat-card success">
          <div className="dashboard-stat-icon">🧪</div>

          <div>
            <span>Tổng sản phẩm</span>
            <strong>{overview.totalProducts}</strong>
            <small>Sẵn sàng cho nghiệp vụ khác</small>
          </div>
        </div>

        <div className="dashboard-stat-card warning">
          <div className="dashboard-stat-icon">🏷️</div>

          <div>
            <span>Nhà cung cấp</span>
            <strong>{totalSuppliers}</strong>
            <small>Từ dữ liệu hiện có</small>
          </div>
        </div>

        <div className="dashboard-stat-card info">
          <div className="dashboard-stat-icon">⭐</div>

          <div>
            <span>Danh mục nổi bật</span>
            <strong>{overview.topCategory?.label || '-'}</strong>
            <small>
              {overview.topCategory
                ? `${overview.topCategory.value} sản phẩm`
                : 'Chưa có dữ liệu'}
            </small>
          </div>
        </div>
      </div>

      <div className="dashboard-chart-grid">
        <PondChartCard
          prefix="product-management"
          title="Số lượng sản phẩm theo danh mục"
          type="doughnut"
          data={categoryChartData}
          total={overview.totalProducts}
        />

        <PondChartCard
          prefix="product-management"
          title="Phân bố nhà cung cấp"
          type="bar"
          data={supplierChartData}
        />

        <PondChartCard
          prefix="product-management"
          title="Sản phẩm sử dụng nhiều"
          type="bar"
          data={productChartData}
        />
      </div>

      <div className="dashboard-tabs">
        <button
          className={activeTab === 'products' ? 'active' : ''}
          onClick={() => setActiveTab('products')}
        >
          Sản phẩm
        </button>

        <button
          className={activeTab === 'categories' ? 'active' : ''}
          onClick={() => setActiveTab('categories')}
        >
          Danh mục
        </button>
      </div>

      {activeTab === 'products' ? (
        <div className="dashboard-table-card">

          <div className="dashboard-table-header">
            <div>
              <h2>Danh sách sản phẩm</h2>
              <p>{filteredProducts.length} sản phẩm hiện có</p>
            </div>
          </div>

          <div className="dashboard-toolbar">

            <input
              type="search"
              placeholder="Tìm sản phẩm..."
              value={productSearch}
              onChange={(e) => {
                setProductSearch(e.target.value)
                setProductPage(1)
              }}
            />

            <input
              type="search"
              placeholder="Tìm nhà cung cấp..."
              value={supplierSearch}
              onChange={(e) => {
                setSupplierSearch(e.target.value)
                setProductPage(1)
              }}
            />

            <select
              value={productCategoryFilter}
              onChange={(e) => {
                setProductCategoryFilter(e.target.value)
                setProductPage(1)
              }}
            >
              <option value="ALL">Tất cả danh mục</option>

              {categories.map((category) => (
                <option
                  key={category.category_id}
                  value={category.category_id}
                >
                  {category.category_name}
                </option>
              ))}
            </select>
          </div>

          <div className="dashboard-table-wrapper">
            <table className="dashboard-table">
              <thead>
                <tr>
                  <th>Sản phẩm</th>
                  <th>Nhà cung cấp</th>
                  <th>Đơn vị</th>
                  <th>Giá</th>
                  <th>Danh mục</th>
                  <th>Cập nhật</th>
                </tr>
              </thead>

              <tbody>
                {paginatedProducts.length > 0 ? (
                  paginatedProducts.map((product) => (
                    <tr key={product.product_id}>
                      <td>
                        <strong>{product.product_name}</strong>
                        <div className="sub-text">{product.product_code}</div>
                      </td>

                      <td>{product.supplier || '-'}</td>

                      <td>{product.unit || '-'}</td>

                      <td>{formatCurrency(product.unit_price)}</td>

                      <td>{product.category_name || '-'}</td>

                      <td>
                        {formatDateTime(product.updated_at || product.created_at)}
                      </td>
                    </tr>
                  ))
                ) : (
                  <tr>
                    <td colSpan="6" className="empty-cell">
                      Không có dữ liệu phù hợp
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        </div>
      ) : (
        <div className="dashboard-table-card">

          <div className="dashboard-table-header">
            <div>
              <h2>Danh sách danh mục</h2>
              <p>{filteredCategories.length} danh mục hiện có</p>
            </div>
          </div>

          <div className="dashboard-toolbar">

            <input
              type="search"
              placeholder="Tìm danh mục..."
              value={categorySearch}
              onChange={(e) => {
                setCategorySearch(e.target.value)
                setCategoryPage(1)
              }}
            />

            <select
              value={categoryFilter}
              onChange={(e) => {
                setCategoryFilter(e.target.value)
                setCategoryPage(1)
              }}
            >
              <option value="ALL">Tất cả</option>
              <option value="HAS_PRODUCTS">Đang có sản phẩm</option>
              <option value="EMPTY">Chưa có sản phẩm</option>
            </select>
          </div>

          <div className="dashboard-table-wrapper">
            <table className="dashboard-table">
              <thead>
                <tr>
                  <th>Danh mục</th>
                  <th>Số lượng sản phẩm</th>
                  <th>Người tạo</th>
                  <th>Cập nhật gần nhất</th>
                </tr>
              </thead>

              <tbody>
                {paginatedCategories.length > 0 ? (
                  paginatedCategories.map((category) => (
                    <tr key={category.category_id}>
                      <td>
                        <strong>{category.category_name}</strong>
                        <div className="sub-text">{category.category_code}</div>
                      </td>

                      <td>{category.product_count || 0}</td>

                      <td>{category.created_by_name || '-'}</td>

                      <td>
                        {formatDateTime(
                          category.latest_activity_at ||
                          category.updated_at ||
                          category.created_at
                        )}
                      </td>
                    </tr>
                  ))
                ) : (
                  <tr>
                    <td colSpan="4" className="empty-cell">
                      Không có dữ liệu phù hợp
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        </div>
      )}
    </div>
  )
}

export default ProductManagementPage
